export const INDEXER_NETWORK_TARGETS = ["mainnet", "local"] as const;

export type IndexerNetworkTarget = (typeof INDEXER_NETWORK_TARGETS)[number];

export interface IndexerTargetConfig {
  canisterIds: string[];
  network: {
    target: IndexerNetworkTarget;
    local: {
      host: string;
      port: number;
    };
  };
}

export const INDEXER_TARGET_CONFIG = {
  canisterIds: ["txyno-ch777-77776-aaaaq-cai"],
  network: {
    target: "local",
    local: {
      host: "localhost",
      port: 8000
    }
  }
} satisfies IndexerTargetConfig;

import websocket from "@fastify/websocket";
import Fastify, { type FastifyBaseLogger, type FastifyInstance } from "fastify";
import { fileURLToPath } from "node:url";

import { resolveIndexerConfig, type IndexerConfigOverrides } from "./config.js";
import { EscrowClient } from "./integrations/escrow-client.js";
import { FactoryClient } from "./integrations/factory-client.js";
import { automatonRoutes } from "./routes/automatons.js";
import { healthRoutes } from "./routes/health.js";
import { realtimeRoutes } from "./routes/realtime.js";
import { spawnSessionRoutes } from "./routes/spawn-sessions.js";
import { createSqliteStore, type IndexerStore } from "./store/sqlite.js";
import "./types.js";
import { RealtimeHub } from "./ws/events.js";

const INDEXER_TARGET_CONFIG_PATH = fileURLToPath(
  new URL("./indexer.config.ts", import.meta.url)
);
const INDEXER_INGESTION_OVERRIDE_VARIABLES = [
  "INDEXER_INGESTION_NETWORK_TARGET",
  "INDEXER_INGESTION_LOCAL_HOST",
  "INDEXER_INGESTION_LOCAL_PORT"
] as const;

export interface BuildServerOptions {
  config?: IndexerConfigOverrides;
  env?: NodeJS.ProcessEnv;
  escrowClient?: EscrowClient;
  factoryClient?: FactoryClient;
  logger?: boolean | FastifyBaseLogger;
  store?: IndexerStore;
  realtimeHub?: RealtimeHub;
}

export function buildServer(options: BuildServerOptions = {}): FastifyInstance {
  const config = resolveIndexerConfig(options.env ?? process.env, options.config);
  const store =
    options.store ??
    createSqliteStore({
      databasePath: config.databasePath
    });
  const factoryClient = options.factoryClient ?? new FactoryClient();
  const escrowClient = options.escrowClient ?? new EscrowClient();
  const realtimeHub = options.realtimeHub ?? new RealtimeHub(config.websocketPath);

  const app = Fastify({
    logger: options.logger ?? false
  });

  app.decorate("escrowClient", escrowClient);
  app.decorate("factoryClient", factoryClient);
  app.decorate("startedAt", Date.now());
  app.decorate("indexerConfig", config);
  app.decorate("indexerStore", store);
  app.decorate("realtimeHub", realtimeHub);

  app.register(websocket);

  app.addHook("onReady", async () => {
    await app.indexerStore.initialize();
  });

  app.addHook("onClose", async () => {
    await Promise.all([
      app.realtimeHub.close(),
      app.indexerStore.close()
    ]);
  });

  app.register(healthRoutes);
  app.register(automatonRoutes);
  app.register(realtimeRoutes);
  app.register(spawnSessionRoutes);

  return app;
}

function isInvalidIngestionConfigError(error: unknown): error is Error {
  return error instanceof Error && error.message.startsWith("Invalid indexer ingestion config:");
}

export function formatStartupError(error: unknown) {
  if (isInvalidIngestionConfigError(error)) {
    return [
      "Indexer startup aborted: invalid ingestion target configuration.",
      `Check ${INDEXER_TARGET_CONFIG_PATH} and runtime overrides ${INDEXER_INGESTION_OVERRIDE_VARIABLES.join(", ")}.`,
      error.message
    ].join("\n");
  }

  return `Failed to start indexer: ${error instanceof Error ? error.stack ?? error.message : String(error)}`;
}

export async function start(
  options: BuildServerOptions & {
    stderr?: Pick<NodeJS.WriteStream, "write">;
  } = {}
) {
  let app: FastifyInstance | undefined;
  const stderr = options.stderr ?? process.stderr;

  try {
    app = buildServer(options);
    await app.listen({
      host: app.indexerConfig.host,
      port: app.indexerConfig.port
    });
  } catch (error) {
    if (app) {
      app.log.error(error);
    } else {
      stderr.write(`${formatStartupError(error)}\n`);
    }
    process.exitCode = 1;
  }
}

if (process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1]) {
  void start();
}

import type { FastifyPluginAsync } from "fastify";

export const healthRoutes: FastifyPluginAsync = async (fastify) => {
  fastify.get("/health", async () => {
    const uptimeMs = Date.now() - fastify.startedAt;
    const database = await fastify.indexerStore.getHealth();
    const { ingestion } = fastify.indexerConfig;
    const targetNetwork =
      ingestion.network.target === "local"
        ? {
            target: ingestion.network.target,
            icHost: fastify.indexerConfig.icHost,
            localReplica: {
              host: ingestion.network.local.host,
              port: ingestion.network.local.port
            }
          }
        : {
            target: ingestion.network.target,
            icHost: fastify.indexerConfig.icHost,
            localReplica: null
          };

    return {
      ok: true,
      service: "indexer",
      uptimeMs,
      timestamp: new Date().toISOString(),
      database,
      discovery: {
        seedCanisterIds: ingestion.canisterIds,
        targetNetwork,
        factoryCanisterId: fastify.indexerConfig.factoryCanisterId ?? null,
        factoryConfigured: fastify.factoryClient.isConfigured(),
        escrowConfigured: fastify.escrowClient.isConfigured()
      },
      realtime: fastify.realtimeHub.getSnapshot(),
      polling: {
        fastIntervalMs: fastify.indexerConfig.fastPollIntervalMs,
        slowIntervalMs: fastify.indexerConfig.slowPollIntervalMs,
        priceIntervalMs: fastify.indexerConfig.pricePollIntervalMs
      }
    };
  });
};

import { fileURLToPath } from "node:url";

import {
  INDEXER_NETWORK_TARGETS,
  INDEXER_TARGET_CONFIG,
  type IndexerTargetConfig
} from "./indexer.config.js";

export interface IndexerConfig {
  host: string;
  port: number;
  databasePath: string;
  websocketPath: string;
  ingestion: IndexerTargetConfig;
  factoryCanisterId?: string;
  icHost: string;
  fastPollIntervalMs: number;
  slowPollIntervalMs: number;
  pricePollIntervalMs: number;
}

export interface IndexerConfigOverrides {
  host?: string;
  port?: number;
  databasePath?: string;
  websocketPath?: string;
  ingestion?: IndexerTargetConfig;
  factoryCanisterId?: string;
  fastPollIntervalMs?: number;
  slowPollIntervalMs?: number;
  pricePollIntervalMs?: number;
}

const DEFAULT_DATABASE_PATH = fileURLToPath(
  new URL("../data/indexer.sqlite", import.meta.url)
);
const BASE32_ALPHABET = "abcdefghijklmnopqrstuvwxyz234567";
const CRC32_TABLE = buildCrc32Table();

function parseNumber(value: string | undefined, fallback: number) {
  if (!value) {
    return fallback;
  }

  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function parseOptionalInteger(value: string | undefined) {
  if (value === undefined) {
    return undefined;
  }

  return Number(value);
}

function buildCrc32Table() {
  const table = new Uint32Array(256);

  for (let index = 0; index < table.length; index += 1) {
    let value = index;

    for (let bit = 0; bit < 8; bit += 1) {
      value = (value & 1) === 0 ? value >>> 1 : (value >>> 1) ^ 0xedb88320;
    }

    table[index] = value >>> 0;
  }

  return table;
}

function computeCrc32(bytes: Uint8Array) {
  let crc = 0xffffffff;

  for (const byte of bytes) {
    crc = CRC32_TABLE[(crc ^ byte) & 0xff] ^ (crc >>> 8);
  }

  return (crc ^ 0xffffffff) >>> 0;
}

function decodeBase32(input: string) {
  const output: number[] = [];
  let buffer = 0;
  let bits = 0;

  for (const character of input) {
    const value = BASE32_ALPHABET.indexOf(character);

    if (value === -1) {
      return null;
    }

    buffer = (buffer << 5) | value;
    bits += 5;

    while (bits >= 8) {
      bits -= 8;
      output.push((buffer >>> bits) & 0xff);
    }
  }

  if (bits > 0 && (buffer & ((1 << bits) - 1)) !== 0) {
    return null;
  }

  return Uint8Array.from(output);
}

function isValidCanisterId(value: string) {
  if (!/^[a-z2-7-]+$/.test(value)) {
    return false;
  }

  const groups = value.split("-");
  if (groups.length === 0 || groups.some((group) => group.length === 0 || group.length > 5)) {
    return false;
  }

  if (groups.slice(0, -1).some((group) => group.length !== 5)) {
    return false;
  }

  const decoded = decodeBase32(groups.join(""));
  if (decoded === null || decoded.length < 4) {
    return false;
  }

  const checksum =
    (decoded[0] << 24) | (decoded[1] << 16) | (decoded[2] << 8) | decoded[3];
  const principal = decoded.slice(4);

  return (checksum >>> 0) === computeCrc32(principal);
}

function validateTargetConfig(config: IndexerTargetConfig) {
  const errors: string[] = [];

  if (!Array.isArray(config.canisterIds) || config.canisterIds.length === 0) {
    errors.push("Indexer ingestion config must include at least one canister ID.");
  }

  for (const [index, canisterId] of config.canisterIds.entries()) {
    if (typeof canisterId !== "string" || !isValidCanisterId(canisterId.trim())) {
      errors.push(
        `Indexer ingestion config canisterIds[${index}] must be a valid canister ID. Received: ${JSON.stringify(canisterId)}.`
      );
    }
  }

  if (!INDEXER_NETWORK_TARGETS.includes(config.network.target)) {
    errors.push(
      `Indexer ingestion config network.target must be one of ${INDEXER_NETWORK_TARGETS.map((target) => JSON.stringify(target)).join(", ")}. Received: ${JSON.stringify(config.network.target)}.`
    );
  }

  if (config.network.target === "local") {
    if (typeof config.network.local.host !== "string" || config.network.local.host.trim() === "") {
      errors.push(
        'Indexer ingestion config network.local.host must be set when network.target is "local".'
      );
    }

    if (!Number.isInteger(config.network.local.port) || config.network.local.port <= 0) {
      errors.push(
        'Indexer ingestion config network.local.port must be set to a positive integer when network.target is "local".'
      );
    }
  }

  if (errors.length > 0) {
    throw new Error(`Invalid indexer ingestion config:\n- ${errors.join("\n- ")}`);
  }
}

function cloneTargetConfig(config: IndexerTargetConfig): IndexerTargetConfig {
  return {
    canisterIds: [...config.canisterIds],
    network: {
      target: config.network.target,
      local: {
        host: config.network.local.host,
        port: config.network.local.port
      }
    }
  };
}

function applyEnvIngestionOverrides(
  config: IndexerTargetConfig,
  env: NodeJS.ProcessEnv
): IndexerTargetConfig {
  const nextConfig = cloneTargetConfig(config);

  if (env.INDEXER_INGESTION_NETWORK_TARGET !== undefined) {
    nextConfig.network.target =
      env.INDEXER_INGESTION_NETWORK_TARGET as IndexerTargetConfig["network"]["target"];
  }

  if (env.INDEXER_INGESTION_LOCAL_HOST !== undefined) {
    nextConfig.network.local.host = env.INDEXER_INGESTION_LOCAL_HOST;
  }

  const localPort = parseOptionalInteger(env.INDEXER_INGESTION_LOCAL_PORT);

  if (localPort !== undefined) {
    nextConfig.network.local.port = localPort;
  }

  return nextConfig;
}

function resolveIcHost(config: IndexerTargetConfig) {
  if (config.network.target === "mainnet") {
    return "https://ic0.app";
  }

  return `http://${config.network.local.host}:${config.network.local.port}`;
}

export function resolveIndexerConfig(
  env: NodeJS.ProcessEnv = process.env,
  overrides: IndexerConfigOverrides = {}
): IndexerConfig {
  const ingestion = applyEnvIngestionOverrides(
    overrides.ingestion ?? INDEXER_TARGET_CONFIG,
    env
  );
  validateTargetConfig(ingestion);

  return {
    host: overrides.host ?? env.HOST ?? "0.0.0.0",
    port: overrides.port ?? parseNumber(env.PORT, 3001),
    databasePath: overrides.databasePath ?? env.INDEXER_DB_PATH ?? DEFAULT_DATABASE_PATH,
    websocketPath: overrides.websocketPath ?? env.INDEXER_WS_PATH ?? "/ws/events",
    ingestion,
    factoryCanisterId:
      overrides.factoryCanisterId ?? env.INDEXER_FACTORY_CANISTER_ID ?? undefined,
    icHost: resolveIcHost(ingestion),
    fastPollIntervalMs:
      overrides.fastPollIntervalMs ?? parseNumber(env.INDEXER_FAST_POLL_INTERVAL_MS, 15_000),
    slowPollIntervalMs:
      overrides.slowPollIntervalMs ?? parseNumber(env.INDEXER_SLOW_POLL_INTERVAL_MS, 300_000),
    pricePollIntervalMs:
      overrides.pricePollIntervalMs ?? parseNumber(env.INDEXER_PRICE_POLL_INTERVAL_MS, 60_000)
  };
}

