120	async function loadSchemaSql() {
121	  const candidates = [
122	    new URL("./schema.sql", import.meta.url),
123	    new URL("../../src/store/schema.sql", import.meta.url)
124	  ];
125	
126	  for (const candidate of candidates) {
127	    try {
128	      await access(candidate);
129	      return await readFile(candidate, "utf8");
130	    } catch {
131	      continue;
132	    }
133	  }
134	
135	  throw new Error("Unable to locate SQLite schema.sql");
136	}
