 79	function isInvalidIngestionConfigError(error: unknown): error is Error {
 80	  return error instanceof Error && error.message.startsWith("Invalid indexer ingestion config:");
 81	}
 82	
 83	export function formatStartupError(error: unknown) {
 84	  if (isInvalidIngestionConfigError(error)) {
 85	    return [
 86	      "Indexer startup aborted: invalid ingestion target configuration.",
 87	      `Check ${INDEXER_TARGET_CONFIG_PATH} and runtime overrides ${INDEXER_INGESTION_OVERRIDE_VARIABLES.join(", ")}.`,
 88	      error.message
 89	    ].join("\n");
 90	  }
 91	
 92	  return `Failed to start indexer: ${error instanceof Error ? error.stack ?? error.message : String(error)}`;
 93	}
