100	  let app: FastifyInstance | undefined;
101	  const stderr = options.stderr ?? process.stderr;
102	
103	  try {
104	    app = buildServer(options);
105	    await app.listen({
106	      host: app.indexerConfig.host,
107	      port: app.indexerConfig.port
108	    });
109	  } catch (error) {
110	    if (app) {
111	      app.log.error(error);
112	    } else {
113	      stderr.write(`${formatStartupError(error)}\n`);
114	    }
115	    process.exitCode = 1;
116	  }
117	}
